import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import response from './response.json';

interface SplitData {
  people: number;
  amountPerPerson: number;
}

interface TipCalculatorData {
  billAmount: number;
  tipPercentage: number;
  tipAmount: number;
  totalWithTip: number;
  split: SplitData[];
}

export default function Widget() {
  const data = response.data as TipCalculatorData;
  const meta = response.meta;

  return (
    <Card
      sx={{
        width: 'fit-content',
        minWidth: 320,
        maxWidth: 450,
        bgcolor: meta.theme === 'light' ? '#FFFFFF' : '#1E1E1E',
      }}
      elevation={2}
    >
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ color: meta.primaryColor }}>
              Tip Calculator
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Bill Amount: ${data.billAmount.toFixed(2)}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Tip Percentage: {data.tipPercentage}%
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Tip Amount: ${data.tipAmount.toFixed(2)}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Total with Tip: ${data.totalWithTip.toFixed(2)}
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" fontWeight={600} sx={{ mb: 1, color: meta.accentColor }}>
              Split Options
            </Typography>
            <Stack direction="row" spacing={0.5}>
              {data.split.map((splitOption, index) => (
                <Chip
                  key={index}
                  label={`${splitOption.people} Person${splitOption.people > 1 ? 's' : ''}: $${splitOption.amountPerPerson.toFixed(2)}`}
                  sx={{ fontSize: '11px', px: 1, py: 0.5, bgcolor: meta.primaryColor, color: 'white' }}
                />
              ))}
            </Stack>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
